const items = $input.all();
const results = [];

items.forEach(item => {
  const data = item.json;

  Object.keys(data)
    .filter(key => 
      !['Name', 'WhatsappNo', 'Email', 'submitted_at', 'id'].includes(key) && 
      data[key] !== '' && data[key] !== null && data[key] !== undefined
    )
    .forEach(key => {
      const val = String(data[key]); 

      // 1. Split by comma OR semicolon OR any other common separator
      const parts = val.split(/[;,]/);

      let totalQty = 0;
      let detectedUnit = "";

      parts.forEach(part => {
        // Extract numeric part (handles integers and decimals)
        const qtyMatch = part.match(/(\d+(\.\d+)?)/);
        if (qtyMatch) {
          totalQty += parseFloat(qtyMatch[0]);
        }

        // Extract the unit (the text part like "kg" or "Nos")
        if (!detectedUnit) {
          const unitMatch = part.replace(/[\d\.]+/, '').trim();
          if (unitMatch) detectedUnit = unitMatch;
        }
      });

      if (totalQty > 0) {
        results.push({
          json: {
            Name: data.Name,
            Mobile: data.WhatsappNo || data.Mobile,
            Email: data.Email,
            ItemName: key,
            Qty: totalQty,       // Results in 3
            Weight: detectedUnit // Results in "kg"
          }
        });
      }
    });
});

return results;

